    var a = v.copy()
    var n = len(a)
    for i in range(n - 1):
        for j in range(n - 1 - i):
            if a[j] > a[j + 1]:
                var t = a[j]
                a[j] = a[j + 1]
                a[j + 1] = t
    if n % 2 == 1:
        return a[n // 2]
    return (a[n // 2 - 1] + a[n // 2]) / 2.0

