def levenshtein(a: String, b: String) -> Int:
    var n = a.byte_length()
    var m = b.byte_length()
    var prev = List[Int]()
    var cur = List[Int]()
    for j in range(m + 1):
        prev.append(j)
        cur.append(0)
    for i in range(1, n + 1):
        cur[0] = i
        for j in range(1, m + 1):
            var cost = 1
            if String(a[byte=i - 1]) == String(b[byte=j - 1]):
                cost = 0
            var d = prev[j] + 1
            var ins = cur[j - 1] + 1
            var sb = prev[j - 1] + cost
            var mn = d
            if ins < mn:
                mn = ins
            if sb < mn:
                mn = sb
            cur[j] = mn
        for j in range(m + 1):
            prev[j] = cur[j]
    return prev[m]

def run_length_encode(s: String) -> String:
    var n = s.byte_length()
    var result = String("")
    var i = 0
    while i < n:
        var c = String(s[byte=i])
        var run = 1
        while i + run < n and String(s[byte=i + run]) == c:
            run += 1
        result += c
        result += String(run)
        i += run
    return result

